<?php namespace App\Domains\RealEstateRental\Policies; use Illuminate\Auth\Access\HandlesAuthorization; class RentalPolicy { use HandlesAuthorization; public function viewAny($user) { return true; } public function view($user, $rental) { return $user->tenant_id === $rental->tenant_id; } public function create($user) { return true; } public function update($user, $rental) { return $user->tenant_id === $rental->tenant_id; } public function delete($user, $rental) { return $user->tenant_id === $rental->tenant_id; } }
